import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Home = () => {
    const [vehicles, setVehicles] = useState([]);

    useEffect(() => {
        const fetchVehicles = async () => {
            try {
                const res = await axios.get('http://localhost:8070/api/vehicles');
                // Only show available vehicles
                setVehicles(res.data.filter(v => v.status === "available"));
            } catch (err) {
                console.error("Error fetching vehicles", err);
            }
        };
        fetchVehicles();
    }, []);

    return (
        <div style={{ padding: '20px' }}>
            <h2>AutoPulse Inventory</h2>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '15px' }}>
                {vehicles.map((v) => (
                    <div key={v._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px' }}>
                        <h3>{v.brand} {v.type} ({v.year})</h3>
                        <p><strong>Price:</strong> LKR {v.price.toLocaleString()}</p>
                        <p><strong>Status:</strong> 
                            <span style={{ color: v.status === 'sold' ? 'red' : 'green' }}> {v.status}</span>
                        </p>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Home;
